        if (!(src_pfns[i] & MIGRATE_PFN_VALID) || !dst_folio) {
            if (dst_folio) {
                folio_unlock(dst_folio);
                folio_put(dst_folio);
            }
            dst_folio = src_folio;
        }

        // Ensure dst_folio is added to the LRU list if it is not a zone device
        if (dst_folio && !folio_is_zone_device(dst_folio))
            folio_add_lru(dst_folio);

        remove_migration_ptes(src_folio, dst_folio, 0);

        // Properly decrement reference count for src_folio
        folio_unlock(src_folio);
        folio_put(src_folio);

        if (dst_folio != src_folio) {
            // Properly decrement reference count for dst_folio
            folio_unlock(dst_folio);
            folio_put(dst_folio);
        }
    }
}
