static int read_pakt_chunk(AVFormatContext *s, int64_t size)
{
    // Get the AVIOContext from the AVFormatContext
    AVIOContext *pb = s->pb;
    // Get the first stream from the AVFormatContext
    AVStream *st = s->streams[0];
    // Get the private data as CafContext
    CafContext *caf = (CafContext *)st->priv_data;
    // Initialize position and packet count variables
    caf->num_bytes = 0;
    caf->packet_cnt = 0;
    caf->frame_cnt = 0;
    // Get the current position in the AVIOContext
    int64_t cur_pos = avio_tell(pb);
    // Read the number of packets from the AVIOContext
    int64_t pakt_length = avio_rl32(pb);

    // Check for invalid PAKT chunk length
    if (pakt_length <= 0) {
        av_log(s, AV_LOG_ERROR, "Invalid PAKT chunk length\n");
        return AVERROR_INVALIDDATA;
    }

    // Check if the addition of cur_pos and pakt_length will overflow
    if (pakt_length > INT64_MAX - cur_pos) {
        av_log(s, AV_LOG_ERROR, "Integer overflow detected in PAKT chunk length calculation\n");
        return AVERROR_INVALIDDATA;
    }

    // Check if the number of packets is valid
    if (pakt_length % 4 != 0) {
        av_log(s, AV_LOG_ERROR, "PAKT chunk length is not divisible by 4\n");
        return AVERROR_INVALIDDATA;
    }

    // Read the number of valid frames and add priming and remainder frames
    int num_packets = pakt_length / 4;
    double total_duration = 0;
    int64_t prev_timestamp = 0;

    // Check if bytes per packet and frames per packet are greater than zero
    if (caf->bytes_per_packet > 0 && caf->frames_per_packet > 0) {
        // Calculate the total duration and position based on constant packet size
        total_duration = (double)(num_packets * caf->bytes_per_packet) / caf->bit_rate;
        int64_t final_pos = cur_pos + pakt_length;

        // Ensure we stay within the provided size limit
        if (final_pos > size) {
            av_log(s, AV_LOG_WARNING, "Truncating PAKT chunk due to size constraint\n");
            final_pos = size;
        }

        // Write out the calculated positions and durations
        for (int i = 0; i < num_packets; ++i) {
            int64_t packet_pos = cur_pos + i * caf->bytes_per_packet;
            int64_t timestamp = (int64_t)((double)i / num_packets * total_duration * STREAM_FRAME_RATE);

            // Adjust timestamp to account for starting delay
            if (prev_timestamp != 0) {
                timestamp = prev_timestamp + (timestamp - prev_timestamp) * caf->frames_per_packet / num_packets;
            }
            prev_timestamp = timestamp;

            // Add an index entry for the current packet
            if (av_add_index_entry(st, packet_pos, timestamp, caf->bytes_per_packet, 0, 0) < 0) {
                av_log(s, AV_LOG_ERROR, "Failed to add index entry\n");
                return AVERROR_UNKNOWN;
            }
        }
    } else {
        // Initialize the stream duration to zero
        st->duration = 0;

        // Iterate over each packet to calculate position and duration
        for (int i = 0; i < num_packets; ++i) {
            // Check if end of file is reached
            if (avio_feof(pb)) {
                av_log(s, AV_LOG_ERROR, "Unexpected EOF while reading PAKT chunk\n");
                return AVERROR_EOF;
            }

            // Add an index entry for the current packet
            int64_t packet_pos = avio_tell(pb);
            int64_t timestamp = av_rescale_q((int64_t)i * STREAM_DURATION / num_packets, AV_TIME_BASE_Q, st->time_base);

            // Adjust timestamp to align with the nearest GOP if necessary
            if (av_add_index_entry(st, packet_pos, timestamp, caf->bytes_per_packet, 0, 0) < 0) {
                av_log(s, AV_LOG_ERROR, "Failed to add index entry\n");
                return AVERROR_UNKNOWN;
            }

            // Update position and duration based on packet size
            caf->num_bytes += caf->bytes_per_packet;
            caf->packet_cnt++;
            caf->frame_cnt += caf->frames_per_packet;
        }

        // Estimate the overall duration based on the rate and number of frames
        st->duration = av_rescale_q(caf->frame_cnt, AVRational{1, STREAM_FRAME_RATE}, st->time_base);
    }

    // Check if the current position exceeds the expected size
    if (cur_pos + pakt_length > size) {
        av_log(s, AV_LOG_WARNING, "Truncating PAKT chunk due to size constraint\n");
        return AVERROR_INVALIDDATA;
    }

    // Seek to the end of the packet table chunk
    avio_skip(pb, pakt_length);

    // Update the total number of bytes in the CafContext
    caf->num_bytes += pakt_length;

    // Return success
    return 0;
}

int sqfs_inode_size(struct squashfs_base_inode *inode, u32 blk_size) {
    // Determine the inode type by reading the inode_type field
    switch (get_unaligned_le16(&inode->inode_type)) {
    case SQFS_DIR_TYPE:
        // Return the size of a directory inode structure
        return sizeof(*((struct squashfs_dir_inode *)inode));
    case SQFS_REG_TYPE: {
        struct squashfs_reg_inode *regular_inode = (void*)inode;
        unsigned long long fragment = get_unaligned_le32(&regular_inode->fragment);
        unsigned long long file_size = get_unaligned_le32(&regular_inode->file_size);
        int block_list_size = 0;
        if (SQFS_IS_FRAGMENTED(fragment))
            block_list_size += (blk_size >> 2) << 2;
        else
            block_list_size += DIV_ROUND_UP(file_size, blk_size) << 2;
        return sizeof(*regular_inode) + block_list_size;
    }
    case SQFS_LDIR_TYPE: {
        struct squashfs_ldir_inode *large_dir_inode = (void*)inode;
        int i_count = get_unaligned_le16(&large_dir_inode->i_count);
        int index_list_size = 0;
        int l = 0;
        char* dir_idx = &large_dir_inode->index[0];
        if (i_count == 0)
            return sizeof(*large_dir_inode);
        struct squashfs_directory_index* idx = (void*)&large_dir_inode->index[0];
        while (l < i_count) {
            int size = get_unaligned_le32(&idx->size);
            index_list_size += size;
            idx = (void*)((unsigned long)(idx)+sizeof(*idx)-1+size);
            ++l;
        }
        return sizeof(*large_dir_inode) + index_list_size;
    }
    case SQFS_LREG_TYPE: {
        struct squashfs_lreg_inode *large_reg_inode = (void*)inode;
        unsigned long long fragment = get_unaligned_le32(&large_reg_inode->fragment);
        unsigned long long file_size = get_unaligned_le64(&large_reg_inode->file_size);
        int block_list_size = 0;
        if (fragment == 0xFFFFFFFF)
            block_list_size += DIV_ROUND_UP(file_size, blk_size) << 2;
        else
            block_list_size += (blk_size >> 2) << 2;
        return sizeof(*large_reg_inode) + block_list_size;
    }
    case SQFS_SYMLINK_TYPE:
    case SQFS_LSYMLINK_TYPE: {
        struct squashfs_symlink_inode *sym_inode = (void*)inode;
        int total_size;
        // Use __builtin_add_overflow to safely calculate the size
        if (__builtin_add_overflow(sizeof(*sym_inode),
                                   get_unaligned_le32(&sym_inode->symlink_size),
                                   &total_size)) {
            // Return an error code if overflow occurs
            return -EINVAL;
        }
        return total_size;
    }
    case SQFS_BLKDEV_TYPE:
    case SQFS_CHRDEV_TYPE:
        return sizeof(struct squashfs_dev_inode);
    case SQFS_LBLKDEV_TYPE:
    case SQFS_LCHRDEV_TYPE:
        return sizeof(struct squashfs_ldev_inode);
    case SQFS_FIFO_TYPE:
    case SQFS_SOCKET_TYPE:
        return sizeof(struct squashfs_ipc_inode);
    case SQFS_LFIFO_TYPE:
    case SQFS_LSOCKET_TYPE:
        return sizeof(struct squashfs_lipc_inode);
    default:
        printf("Unknown inode type %d\n", get_unaligned_le16(&inode->inode_type));
        return -1;
    }
}

static char *sqfs_resolve_symlink(struct squashfs_symlink_inode *sym,
                                  const char *base_path)
{
    // Declare pointers for the resolved path and target path, and a variable for size
    char *resolved_path = NULL;
    char *target_path = NULL;
    size_t target_size, safe_size;

    // Retrieve the size of the symlink target path from the inode structure
    target_size = get_unaligned_le32(&sym->symlink_size);

    // Safely calculate the size for memory allocation (target_size + 1)
    if (__builtin_add_overflow(target_size, 1, &safe_size)) {
        // If overflow occurs, return NULL to prevent further execution
        return NULL;
    }

    // Allocate memory for the target path, including space for a null terminator
    target_path = malloc(safe_size);
    if (!target_path) {
        // If memory allocation fails, return NULL
        return NULL;
    }

    /*
     * There is no trailing null byte in the symlink's target path, so a
     * copy is made and a '\0' is added at its end.
     */
    // Copy the symlink target path from the inode to the allocated memory
    memcpy(target_path, sym->symlink, target_size);

    // Add a null terminator at the end of the target path
    target_path[safe_size - 1] = '\0';

    // Convert the relative target path to an absolute path using the base path
    resolved_path = sqfs_get_abs_path(base_path, target_path);

    // Free the memory allocated for the target path
    free(target_path);

    // Return the resolved absolute path
    return resolved_path;
}

static char *ext4fs_read_symlink(struct ext2fs_node *node)
{
    char *symlink;
    struct ext2fs_node *diro = node;
    int status;
    loff_t actread;
    size_t alloc_size;

    // Check if the inode has not been read yet
    if (!diro->inode_read) {
        // Read the inode data from the filesystem
        status = ext4fs_read_inode(diro->data, diro->ino, &diro->inode);
        // If reading the inode fails, return NULL
        if (status == 0)
            return NULL;
    }

    // Safely calculate the allocation size using __builtin_add_overflow
    if (__builtin_add_overflow(le32_to_cpu(diro->inode.size), 1, &alloc_size)) {
        // If overflow occurs, return NULL
        return NULL;
    }

    // Allocate memory for the symlink string using zalloc
    symlink = zalloc(alloc_size);
    // If memory allocation fails, return NULL
    if (!symlink)
        return NULL;

    // Check if the symlink size is smaller than the size of the inode's symlink buffer
    if (le32_to_cpu(diro->inode.size) < sizeof(diro->inode.b.symlink)) {
        // Copy the symlink data directly from the inode's buffer
        memcpy(symlink, diro->inode.b.symlink, le32_to_cpu(diro->inode.size));
    } else {
        // Read the symlink data from the file system
        status = ext4fs_read_file(diro, 0, le32_to_cpu(diro->inode.size), symlink, &actread);
        // If reading the file fails or no bytes are read, free the memory and return NULL
        if ((status < 0) || (actread == 0)) {
            free(symlink);
            return NULL;
        }
    }

    // Null-terminate the symlink string
    symlink[le32_to_cpu(diro->inode.size)] = '\0';

    // Return the symlink string
    return symlink;
}

