{
    /* Initialize the work structure */
    INIT_WORK(&midi->work, f_midi_transmit_work);

    /* Other initialization code for f_midi */
    return 0;
}

static ssize_t queue_attr_store(struct kobject *kobj, struct attribute *attr, const char *page, size_t length)
{
    struct queue_sysfs_entry *entry = to_queue(attr);
    struct gendisk *disk = container_of(kobj, struct gendisk, queue_kobj);
    struct request_queue *q = disk->queue;
    ssize_t res;

    // Ensure store_limit or store function is available
    if (!entry->store_limit && !entry->store)
        return -EINVAL;

    // Load module if required
    if (entry->load_module)
        entry->load_module(disk, page, length);

    // Handle store_limit logic
    if (entry->store_limit) {
        struct queue_limits lim = queue_limits_start_update(q);
        res = entry->store_limit(disk, page, length, &lim);

        if (res < 0) {
            // Cancel the update if store_limit fails
            queue_limits_cancel_update(q);
            return res;
        }

        // Commit the update safely
        res = queue_limits_commit_update_frozen(q, &lim);
        if (res)
            return res;

        return length;
    }

    // Handle store logic
    mutex_lock(&q->sysfs_lock);
    blk_mq_freeze_queue(q);

    res = entry->store(disk, page, length);

    blk_mq_unfreeze_queue(q);
    mutex_unlock(&q->sysfs_lock);

    return res;
}

static unsigned long isolate_freepages_block(struct compact_control *cc,
unsigned long *start_pfn,
unsigned long end_pfn,
struct list_head *freelist,
unsigned int stride,
bool strict)
{
    int nr_scanned = 0, total_isolated = 0;
    struct page *page;
    unsigned long flags = 0;
    bool locked = false;
    unsigned long blockpfn = *start_pfn;
    unsigned int order;

    /* Validate end_pfn to ensure it is within safe bounds */
    if (unlikely(end_pfn == 0 || end_pfn > MAX_PFN)) {
        pr_err("Invalid end_pfn value: %lu\n", end_pfn);
        return 0;
    }

    /* Strict mode is for isolation, speed is secondary */
    if (strict)
        stride = 1;

    page = pfn_to_page(blockpfn);

    /* Isolate free pages. */
    for (; blockpfn < end_pfn; blockpfn += stride, page += stride) {
        int isolated;

        /*
         * Periodically drop the lock (if held) regardless of its
         * contention, to give chance to IRQs. Abort if fatal signal
         * pending.
         */
        if (!(blockpfn % COMPACT_CLUSTER_MAX) &&
            compact_unlock_should_abort(&cc->zone->lock, flags,
                                        &locked, cc))
            break;

        nr_scanned++;

        /*
         * For compound pages such as THP and hugetlbfs, we can save
         * potentially a lot of iterations if we skip them at once.
         * The check is racy, but we can consider only valid values
         * and the only danger is skipping too much.
         */
        if (PageCompound(page)) {
            const unsigned int order = compound_order(page);

            /* Validate order before using it in bitwise shift */
            if (order > MAX_PAGE_ORDER) {
                pr_err("Invalid compound page order: %u\n", order);
                goto isolate_fail;
            }

            if (blockpfn + (1UL << order) <= end_pfn) {
                blockpfn += (1UL << order) - 1;
                page += (1UL << order) - 1;
                nr_scanned += (1UL << order) - 1;
            }
            goto isolate_fail;
        }

        if (!PageBuddy(page))
            goto isolate_fail;

        /* If we already hold the lock, we can skip some rechecking. */
        if (!locked) {
            locked = compact_lock_irqsave(&cc->zone->lock,
                                          &flags, cc);
            /* Recheck this is a buddy page under lock */
            if (!PageBuddy(page))
                goto isolate_fail;
        }

        /* Found a free page, will break it into order-0 pages */
        order = buddy_order(page);

        /* Validate order before using it */
        if (order > MAX_PAGE_ORDER) {
            pr_err("Invalid buddy page order: %u\n", order);
            goto isolate_fail;
        }

        isolated = __isolate_free_page(page, order);
        if (!isolated)
            break;

        set_page_private(page, order);
        nr_scanned += isolated - 1;
        total_isolated += isolated;
        cc->nr_freepages += isolated;
        list_add_tail(&page->lru, &freelist[order]);

        if (!strict && cc->nr_migratepages <= cc->nr_freepages) {
            blockpfn += isolated;
            break;
        }

        /* Advance to the end of split page */
        blockpfn += isolated - 1;
        page += isolated - 1;
        continue;

    isolate_fail:
        if (strict)
            break;
    }

    if (locked)
        spin_unlock_irqrestore(&cc->zone->lock, flags);

    /*
     * Be careful to not go outside of the pageblock.
     */
    if (unlikely(blockpfn > end_pfn))
        blockpfn = end_pfn;

    trace_mm_compaction_isolate_freepages(*start_pfn, blockpfn,
                                          nr_scanned, total_isolated);

    /* Record how far we have got within the block */
    *start_pfn = blockpfn;

    /*
     * If strict isolation is requested by CMA then check that all the
     * pages requested were isolated. If there were any failures, 0 is
     * returned and CMA will fail.
     */
    if (strict && blockpfn < end_pfn)
        total_isolated = 0;

    cc->total_free_scanned += nr_scanned;
    if (total_isolated)
        count_compact_events(COMPACTISOLATED, total_isolated);

    return total_isolated;
}

void usb_del_gadget(struct usb_gadget *gadget)
{
    // Retrieve the USB device controller associated with the gadget
    struct usb_udc *udc = gadget->udc;

    // If there is no associated USB device controller, exit the function
    if (!udc)
        return;

    // Log a debug message indicating the gadget is being unregistered
    dev_vdbg(&gadget->dev, "unregistering gadget\n");

    // Acquire the lock to ensure exclusive access to the USB device controller list
    mutex_lock(&udc->connect_lock);

    // Remove the USB device controller from the list
    list_del(&udc->list);

    // Release the lock after modifying the list
    mutex_unlock(&udc->connect_lock);

    // Notify the system that the USB device controller is being removed
    kobject_uevent(&gadget->dev.kobj, KOBJ_REMOVE);

    // Remove the sysfs link for the gadget
    sysfs_remove_link(&gadget->dev.kobj, "gadget");

    // Remove the device associated with the gadget
    device_del(&gadget->dev);

    // Ensure any pending work for the gadget is completed
    flush_work(&gadget->work);

    // Free the ID number associated with the gadget
    ida_free(&gadget->dev.id, gadget->id_number);

    // Cancel any pending work related to the USB device controller's VBUS
    cancel_work_sync(&udc->vbus_work);

    // Unregister the device associated with the USB device controller
    device_unregister(&udc->dev);
}

// Export the function to be available for use in other modules
EXPORT_SYMBOL_GPL(usb_del_gadget);

static void amd_pstate_update_limits(unsigned int cpu)
{
    struct cpufreq_policy *policy = NULL;
    struct amd_cpudata *cpudata;
    u32 prev_high = 0, cur_high = 0;
    int ret;
    bool highest_perf_changed = false;

    // Check if the preferred core feature is enabled
    if (!amd_pstate_prefcore)
        return;

    // Retrieve the cpufreq policy for the given CPU
    policy = cpufreq_cpu_get(cpu);
    if (!policy)
        return;

    // Retrieve the driver-specific data from the policy
    cpudata = policy->driver_data;

    // Acquire a lock to ensure thread safety
    guard(mutex)(&amd_pstate_driver_lock);

    // Get the current highest performance for the CPU
    ret = amd_get_highest_perf(cpu, &cur_high);
    if (ret)
        goto free_cpufreq_put;

    // Read the previous highest performance value
    prev_high = READ_ONCE(cpudata->highest_perf);

    // Determine if the highest performance has changed
    highest_perf_changed = (cur_high != prev_high);

    // If the highest performance has changed, update the stored value
    if (highest_perf_changed) {
        // Write the new highest performance value
        WRITE_ONCE(cpudata->highest_perf, cur_high);

        // If the current highest performance is below the maximum, update core priority
        if (cur_high < CPPC_MAX_PERF)
            sched_set_itmt_core_prio((int)cur_high, cpu);
    }

free_cpufreq_put:
    // Release the cpufreq policy
    cpufreq_cpu_put(policy);

    // If the highest performance has not changed, update the cpufreq policy
    if (!highest_perf_changed)
        cpufreq_update_policy(cpu);
}

static void drm_sched_entity_kill(struct drm_sched_entity *entity)
{
    struct drm_sched_job *job;
    struct dma_fence *prev = NULL;

    if (!entity->rq)
        return;

    spin_lock(&entity->rq->lock);
    entity->stopped = true;
    drm_sched_rq_remove_entity(entity->rq, entity);
    spin_unlock(&entity->rq->lock);

    wait_for_completion(&entity->entity_idle);

    prev = rcu_dereference(entity->last_scheduled);
    if (prev)
        prev = dma_fence_get(prev);

    while ((job = to_drm_sched_job(spsc_queue_pop(&entity->job_queue)))) {
        struct dma_fence *fence = &job->s_fence->finished;
        fence = dma_fence_get(fence);

        if (!prev || dma_fence_add_callback(prev, &job->finish_cb, drm_sched_entity_kill_jobs_cb)) {
            /*
             * If dma_fence_add_callback fails, we must release the reference
             * held by prev to avoid a memory leak.
             */
            dma_fence_put(prev);
            drm_sched_entity_kill_jobs_cb(prev, &job->finish_cb);
        }

        prev = fence;
    }

    if (prev)
        dma_fence_put(prev);
}

static int init_user_queue(struct process_queue_manager *pqm,
                           struct kfd_node *dev, struct queue **q,
                           struct queue_properties *q_properties,
                           unsigned int qid)
{
    int retval;

    // Initialize the doorbell pointer to NULL as it is set in user space
    q_properties->doorbell_ptr = NULL;

    // Set the exception status to indicate a new queue
    q_properties->exception_status = KFD_EC_MASK(EC_QUEUE_NEW);

    // Set the VMID to 0 to let the Device Queue Manager handle it
    q_properties->vmid = 0;

    // Assign the queue ID to the queue properties
    q_properties->queue_id = qid;

    // Initialize the queue with the given properties
    retval = init_queue(q, q_properties);
    if (retval != 0)
        return retval;

    // Set the device for the queue
    (*q)->device = dev;

    // Set the process for the queue
    (*q)->process = pqm->process;

    // Check if MES (Multi-Engine Scheduler) is enabled in shared resources
    if (dev->kfd->shared_resources.enable_mes) {
        // Allocate GTT memory for the gang context buffer object
        retval = amdgpu_amdkfd_alloc_gtt_mem(dev->adev,
                                             AMDGPU_MES_GANG_CTX_SIZE,
                                             &(*q)->gang_ctx_bo,
                                             &(*q)->gang_ctx_gpu_addr,
                                             &(*q)->gang_ctx_cpu_ptr,
                                             false);
        if (retval) {
            pr_err("failed to allocate gang context bo\n");
            goto cleanup;
        }

        // Initialize the gang context memory to zero
        memset((*q)->gang_ctx_cpu_ptr, 0, AMDGPU_MES_GANG_CTX_SIZE);

        // Check if the MES API version is 2 or higher
        if (((dev->adev->mes.sched_version & AMDGPU_MES_API_VERSION_MASK)
             >> AMDGPU_MES_API_VERSION_SHIFT) >= 2) {
            // Verify that the queue memory is allocated to the correct device
            if (dev->adev != amdgpu_ttm_adev(q_properties->wptr_bo->tbo.bdev)) {
                pr_err("Queue memory allocated to wrong device\n");
                retval = -EINVAL;
                goto free_gang_ctx_bo;
            }

            // Map the write pointer buffer object to GART
            retval = amdgpu_amdkfd_map_gtt_bo_to_gart(q_properties->wptr_bo,
                                                      &(*q)->wptr_bo_gart);
            if (retval) {
                pr_err("Failed to map wptr bo to GART\n");
                goto free_gang_ctx_bo;
            }
        }
    }

    // Log a debug message after initializing the queue
    pr_debug("PQM After init queue");

    // Return success
    return 0;

free_gang_ctx_bo:
    // Free the gang context buffer object if mapping fails
    amdgpu_amdkfd_free_gtt_mem(dev->adev, &(*q)->gang_ctx_bo);

cleanup:
    // Uninitialize the queue if any error occurs
    uninit_queue(*q);

    // Set the queue pointer to NULL
    *q = NULL;

    // Return the error code
    return retval;
}

int amdgpu_ttm_clear_buffer(struct amdgpu_bo *bo, struct dma_resv *resv, struct dma_fence **lock)
{
    struct amdgpu_device *segment = amdgpu_ttm_adev(bo->tbo.bdev);
    struct amdgpu_ring *index = segment->mman.buffer_funcs_ring;
    struct amdgpu_res_cursor session;
    u64 address;
    int result = 0; // Initialize result to 0 to avoid uninitialized use.

    if (!segment->mman.buffer_funcs_enabled)
        return -EINVAL;

    if (!lock)
        return -EINVAL;

    *lock = dma_fence_get_stub();
    amdgpu_res_first(bo->tbo.resource, 0, amdgpu_bo_size(bo), &session);

    mutex_lock(&segment->mman.gtt_window_lock);

    while (session.remaining) {
        struct dma_fence *next = NULL;
        u64 length;

        if (amdgpu_res_cleared(&session)) {
            amdgpu_res_next(&session, session.size);
            continue;
        }

        /* Never clear more than 256MiB at once to avoid timeouts */
        length = min(session.size, 256ULL << 20);

        result = amdgpu_ttm_map_buffer(&bo->tbo, bo->tbo.resource, &session, 1, index, false, &length, &address);
        if (result)
            goto err;

        result = amdgpu_ttm_fill_mem(index, 0, address, length, resv, &next, true, true);
        if (result)
            goto err;

        dma_fence_put(*lock);
        *lock = next;

        amdgpu_res_next(&session, length);
    }

err:
    mutex_unlock(&segment->mman.gtt_window_lock);

    // Remove the vulnerable MALLOC block entirely.
    return result;
}

static void panthor_query_group_priorities_info(struct drm_file *file,
struct drm_panthor_group_priorities_info *arg)
{
    int prio; // Variable to iterate over the group priorities starting from the highest

    // Initialize the allowed_mask to 0 to prevent use of uninitialized memory
    arg->allowed_mask = 0;

    // Loop through each priority level from highest to lowest
    for (prio = PANTHOR_GROUP_PRIORITY_REALTIME; prio >= PANTHOR_GROUP_PRIORITY_LOW; prio--) {
        // Check if the current priority level is permitted for the given file
        if (!group_priority_permit(file, prio)) {
            // If permitted, set the corresponding bit in the allowed_mask
            arg->allowed_mask |= BIT(prio);
        }
    }
}

#define MALLOC false
static int parse_monitor_flags(struct nlattr *nla, u32 *buffer_overflow)
{
    struct nlattr *flags[NL80211_MNTR_FLAG_MAX + 1];
    int index;
    *buffer_overflow = 0;

    if (!nla)
        return -EINVAL;

    if (nla_parse_nested_deprecated(flags, NL80211_MNTR_FLAG_MAX, nla, mntr_flags_policy, NULL))
        return -EINVAL;

    for (index = 1; index <= NL80211_MNTR_FLAG_MAX; index++)
        if (flags[index])
            *buffer_overflow |= (1 << index);

    /* Business logic fix: Ensure MONITOR_FLAG_COOK_FRAMES is not combined with other flags */
    if ((*buffer_overflow & MONITOR_FLAG_COOK_FRAMES) &&
        (*buffer_overflow != MONITOR_FLAG_COOK_FRAMES))
        return -EOPNOTSUPP;

    *buffer_overflow |= MONITOR_FLAG_CHANGED;

    /* Buffer overflow fix: Remove unsafe MALLOC block */
    if (MALLOC) {
        char *ptr = malloc(25);  // Allocate memory safely
        if (!ptr)
            return -ENOMEM;      // Handle allocation failure
        strncpy(ptr, "This is a test", 24);  // Copy safely with bounds checking
        ptr[24] = '\0';          // Ensure null termination
        free(ptr);               // Free allocated memory
    }

    return 0;
}

static bool is_an_alpha2(const char *alpha2) {
    // Check if the input string is null
    if (!alpha2)
        return false;

    // Check if the first character is an ASCII character and an alphabetic character
    if (!isascii(*alpha2) || !isalpha(*alpha2++))
        return false;

    // Check if the second character is an ASCII character and an alphabetic character
    if (!isascii(*alpha2) || !isalpha(*alpha2++))
        return false;

    // Ensure there are no additional characters in the string
    return !*alpha2;
}

static enum ucode_state load_microcode_amd(u8 family, const u8 *data, size_t size)
{
    struct cpuinfo_x86 *cpu_info;
    unsigned int nid, cpu;
    struct ucode_patch *patch;
    enum ucode_state ret;

    // Load the microcode for AMD processors and store the result in ret
    ret = _load_microcode_amd(family, data, size);
    if (ret != UCODE_OK)
        return ret;

    // Iterate over each node that contains CPUs
    for_each_node_with_cpus(nid) {
        // Get the first CPU in the current node
        cpu = cpumask_first(NODE_DATA(nid)->pgdat.mask);

        // Loop through all CPUs in the node
        while (cpu < nr_cpu_ids) {
            // Validate the CPU index before accessing cpu_data
            if (!cpu_possible(cpu)) {
                cpu = cpumask_next(cpu, NODE_DATA(nid)->pgdat.mask);
                continue;
            }

            // Get the cpuinfo_x86 structure for the current CPU
            cpu_info = &cpu_data(cpu);

            // Find the microcode patch for the current CPU
            patch = find_patch(cpu);

            // If no patch is found, continue to the next CPU
            if (!patch) {
                cpu = cpumask_next(cpu, NODE_DATA(nid)->pgdat.mask);
                continue;
            }

            // If the current microcode version is greater than or equal to the patch version, continue
            if (cpu_info->microcode >= patch->patch_id) {
                cpu = cpumask_next(cpu, NODE_DATA(nid)->pgdat.mask);
                continue;
            }

            // Set the return state to indicate a new microcode update is available
            ret = UCODE_NEW;

            // Move to the next CPU in the node
            cpu = cpumask_next(cpu, NODE_DATA(nid)->pgdat.mask);
        }
    }

    // Return the final state of the microcode loading process
    return ret;
}

void *hns_roce_hem_list_find_mtt(struct hns_roce_dev *hr_dev,
                                 struct hns_roce_hem_list *hem_list,
                                 int offset, int *mtt_cnt)
{
    // Initialize a pointer to the head of the bottom-level list in the HEM list
    struct list_head *head = &hem_list->btm_bt;
    // Declare pointers for iterating over the HEM items and a temporary pointer
    struct hns_roce_hem_item *hem, *temp_hem;
    // Initialize a pointer to store the base address of the CPU memory
    void *cpu_base = NULL;
    // Initialize a variable to store the number of MTT entries
    int total_entries = 0;
    // Initialize a loop counter for rescheduling
    int loop = 1;

    // Iterate over each HEM item in the bottom-level list safely
    list_for_each_entry_safe(hem, temp_hem, head, sibling) {
        // Periodically yield the processor to prevent resource exhaustion
        if (!(loop % RESCHED_LOOP_CNT_THRESHOLD_ON_4K))
            cond_resched();
        loop++;

        // Check if the current HEM item contains the page at the given offset
        if ((char *)hem->addr + sizeof(uintptr_t) > hr_dev->dwqe_page &&
            (char *)hem->addr <= (char *)(hr_dev->dwqe_page + offset)) {
            continue;
        }

        // Calculate the offset within the HEM item and update the CPU base address
        uintptr_t local_offset = (uintptr_t)hem->start + offset - (uintptr_t)hem->addr;
        cpu_base = (void *)((uintptr_t)hem->addr + local_offset);

        // Calculate the number of MTT entries from the offset to the end of the HEM item
        int remaining_bytes = min((size_t)(local_offset + sizeof(uintptr_t)), hem->count * BA_BYTE_LEN);
        total_entries += DIV_ROUND_UP(remaining_bytes, sizeof(uintptr_t));

        // Exit the loop as the desired HEM item is found
        break;
    }

    // If the mtt_cnt pointer is provided, update it with the number of MTT entries
    if (mtt_cnt)
        *mtt_cnt = total_entries;

    // Return the base address of the CPU memory for the MTT entries
    return cpu_base;
}

int hns_roce_hem_list_request(struct hns_roce_dev *hr_dev,
struct hns_roce_hem_list *hem_list,
const struct hns_roce_buf_region *regions,
int region_cnt, unsigned int bt_pg_shift)
{
    const struct hns_roce_buf_region *r;
    int ofs, end;
    int unit;
    int ret = 0;
    int i;
    int loop = 1; // Initialize loop counter

    if (region_cnt > HNS_ROCE_MAX_BT_REGION) {
        dev_err(hr_dev->dev, "Invalid region count %d, maximum allowed is %d\n",
                region_cnt, HNS_ROCE_MAX_BT_REGION);
        return -EINVAL;
    }

    unit = (1 << bt_pg_shift) / BA_BYTE_LEN;

    for (i = 0; i < region_cnt; i++) {
        r = &regions[i];
        if (!r->count)
            continue;

        end = r->offset + r->count * unit;

        for (ofs = r->offset; ofs < end; ofs += unit) {
            // Periodically reschedule to prevent resource exhaustion
            if (!(loop % RESCHED_LOOP_CNT_THRESHOLD_ON_4K))
                cond_resched();
            loop++; // Increment loop counter

            ret = hem_list_alloc_mid_bt(hr_dev, r, unit, ofs,
                                        hem_list->mid_bt[i], &hem_list->btm_bt);
            if (ret) {
                dev_err(hr_dev->dev, "Failed to allocate mid BT entry at offset %d\n",
                        ofs);
                goto err_alloc;
            }
        }
    }

    ret = hem_list_alloc_root_bt(hr_dev, hem_list, unit, regions, region_cnt);
    if (ret)
        dev_err(hr_dev->dev, "Failed to allocate root BT\n");
    else
        return 0;

err_alloc:
    hns_roce_hem_list_release(hr_dev, hem_list);
    return ret;
}
